const { ApolloServer, gql } = require('apollo-server');

const typeDefs = gql`
  type Invoice {
    id: ID!
    invoiceNumber: String!
    date: String!
    dueDate: String!
    status: String!
    customerId: String!
    customerName: String!
    customerEmail: String!
    items: [InvoiceItem!]!
    subtotal: Float!
    tax: Float!
    total: Float!
    notes: String
    createdAt: String!
    updatedAt: String!
  }

  type InvoiceItem {
    id: ID!
    description: String!
    quantity: Int!
    unitPrice: Float!
    total: Float!
  }

  type Query {
    invoice(id: ID!): Invoice
  }
`;

