const resolvers = {
  Query: {
    invoice: (parent, args, context) => {
      const { id } = args;
      const invoice = invoicesDB.find(inv => inv.id === id);
      return invoice || null;
    }
  }
};

const server = new ApolloServer({
  typeDefs,
  resolvers,
  context: ({ req }) => {
    return {
      user: req.user
    };
  }
});

